import React, { useState, useRef } from "react";
import FileUpload from "./components/FileUpload";
import Results from "./components/Results";
import "./App.css";

export default function App() {
  const [result, setResult]   = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState(null);
  const [steps, setSteps]     = useState([]);
  const [pct, setPct]         = useState(0);
  const [silLive, setSilLive] = useState({});

  const handleUpload = async (file) => {
    setLoading(true);
    setError(null);
    setResult(null);
    setSteps([]);
    setPct(0);
    setSilLive({});

    const formData = new FormData();
    formData.append("file", file);

    try {
      const res = await fetch("http://localhost:8000/cluster", {
        method: "POST",
        body: formData,
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.detail || "Server error");
      }

      // Read the SSE stream manually
      const reader  = res.body.getReader();
      const decoder = new TextDecoder();
      let   buffer  = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const parts = buffer.split("\n\n");
        buffer = parts.pop(); // keep incomplete last chunk

        for (const part of parts) {
          if (!part.trim()) continue;

          // Parse event type and data from SSE chunk
          let eventType = "message";
          let dataLine  = "";
          for (const line of part.split("\n")) {
            if (line.startsWith("event: ")) eventType = line.slice(7).trim();
            if (line.startsWith("data: "))  dataLine  = line.slice(6).trim();
          }
          if (!dataLine) continue;

          let payload;
          try { payload = JSON.parse(dataLine); }
          catch { continue; }

          if (eventType === "step") {
            setPct(payload.pct ?? 0);
            if (payload.sil_scores) setSilLive({ ...payload.sil_scores });
            setSteps((prev) => {
              // Replace step with same stage key, or append
              const idx = prev.findIndex((s) => s.stage === payload.stage);
              const updated = [...prev];
              if (idx >= 0) updated[idx] = payload;
              else updated.push(payload);
              return updated;
            });
          } else if (eventType === "error") {
            throw new Error(payload.message || "Pipeline error");
          } else if (eventType === "done") {
            setResult(payload);
          }
        }
      }
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setResult(null);
    setError(null);
    setSteps([]);
    setPct(0);
    setSilLive({});
  };

  return (
    <div className="app">
      <div className="bg-grid" aria-hidden="true" />

      <header className="header">
        <div className="header-inner">
          <div className="logo">
            <span className="logo-mark">◈</span>
            <span className="logo-text">RFM<span className="logo-accent">seg</span></span>
          </div>
          <p className="header-sub">Customer Segmentation Engine</p>
        </div>
      </header>

      <main className="main">
        {!result && !loading && (
          <FileUpload onUpload={handleUpload} error={error} />
        )}
        {loading && (
          <LoadingState steps={steps} pct={pct} silLive={silLive} />
        )}
        {result && <Results data={result} onReset={handleReset} />}
      </main>
    </div>
  );
}

// ── Stage metadata ─────────────────────────────────────────────────────────
const STAGE_META = {
  parse:        { icon: "📂", label: "Reading file" },
  columns:      { icon: "🔍", label: "Mapping columns" },
  clean:        { icon: "🧹", label: "Cleaning data" },
  monetary:     { icon: "💰", label: "Computing spend" },
  frequency:    { icon: "🔁", label: "Computing frequency" },
  monetary_agg: { icon: "📊", label: "Aggregating monetary" },
  recency:      { icon: "📅", label: "Computing recency" },
  rfm:          { icon: "🧮", label: "Building RFM table" },
  scale:        { icon: "⚖️",  label: "Scaling features" },
  best_k:       { icon: "✅", label: "Best k selected" },
  profiles:     { icon: "🏷️",  label: "Profiling segments" },
};
// k2..k8 handled dynamically below

function LoadingState({ steps, pct, silLive }) {
  const logRef = useRef(null);

  React.useEffect(() => {
    if (logRef.current) {
      logRef.current.scrollTop = logRef.current.scrollHeight;
    }
  }, [steps]);

  const currentStep = steps[steps.length - 1];
  const hasSil = Object.keys(silLive).length > 0;
  const bestK  = hasSil ? Object.entries(silLive).sort((a,b)=>b[1]-a[1])[0]?.[0] : null;

  return (
    <div className="loading-page">

      {/* ── Left: progress panel ── */}
      <div className="loading-left">
        <div className="progress-header">
          <span className="progress-title">Processing…</span>
          <span className="progress-pct">{pct}%</span>
        </div>

        <div className="progress-track">
          <div className="progress-fill" style={{ width: `${pct}%` }} />
        </div>

        {currentStep && (
          <div className="current-stage">
            <span className="current-icon">
              {STAGE_META[currentStep.stage]?.icon
                ?? (currentStep.stage.startsWith("k") ? "🔬" : "⚙️")}
            </span>
            <div>
              <p className="current-title">{currentStep.title}</p>
              <p className="current-detail">{currentStep.detail}</p>
            </div>
          </div>
        )}

        {/* ── Live silhouette mini-chart ── */}
        {hasSil && (
          <div className="sil-live">
            <p className="sil-live-label">Silhouette scores (live)</p>
            <div className="sil-bars">
              {Object.entries(silLive).map(([k, v]) => (
                <div key={k} className="sil-bar-col">
                  <div className="sil-bar-track">
                    <div
                      className={`sil-bar-fill ${String(k) === String(bestK) ? "best" : ""}`}
                      style={{ height: `${Math.round(v * 100)}%` }}
                    />
                  </div>
                  <span className="sil-bar-score">{v.toFixed(3)}</span>
                  <span className="sil-bar-k">k={k}</span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* ── Right: step log ── */}
      <div className="loading-right">
        <p className="log-label">Pipeline log</p>
        <div className="step-log" ref={logRef}>
          {steps.length === 0 && (
            <p className="log-empty">Waiting for server…</p>
          )}
          {steps.map((s, i) => (
            <div key={s.stage} className={`log-row ${s.warn ? "log-warn" : ""} ${i === steps.length - 1 ? "log-active" : "log-done"}`}>
              <span className="log-icon">
                {i === steps.length - 1
                  ? <span className="log-spinner" />
                  : "✓"}
              </span>
              <div className="log-text">
                <span className="log-title">{s.title}</span>
                <span className="log-detail">{s.detail}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
